for (let i = 1; i <= 133; i++) {
  let kwh = flow.get('kwh_' + i) || 0;
  kwh += Math.random() * 0.03;
  flow.set('kwh_' + i, kwh);
  node.send({ topic: 'meter/' + i + '/kwh', payload: kwh });
}
return null;

let topic = msg.topic;
let id = topic.split('/')[1];
let current = parseFloat(msg.payload);

let last = flow.get('last_' + id) || current;
let usage = current - last;
if (usage < 0) usage = 0;
flow.set('last_' + id, current);

let tariff = 0.50;
let balance = flow.get('bal_' + id) || 50;

let cost = usage * tariff;
balance -= cost;

flow.set('bal_' + id, balance);

msg.meter_id = id;
msg.usage = usage;
msg.balance = balance;

return msg;

let id = msg.meter_id;

if (msg.balance <= 0) {
  return { topic: 'meter/' + id + '/control', payload: 'OFF' };
} else {
  return { topic: 'meter/' + id + '/control', payload: 'ON' };
}

let id = msg.topic.split('/')[1];
let amount = parseFloat(msg.payload);

let balance = flow.get('bal_' + id) || 0;
balance += amount;

flow.set('bal_' + id, balance);

return { topic: 'meter/' + id + '/status', payload: 'Topup OK: ' + balance };
